INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'rochester'), 'R-1', 'r-1', 'Low-Density Residential District', 'The R-1 Low-Density Residential District is intended to maintain residential areas at relatively low densities, characterized predominantly by owner-occupied, single-family detached and attached homes, while preserving unobstructed front yards and pedestrian-scale streetscapes.', 35, NULL, '[object Object]', 50, 'Average of 2 adjoining lots or block frontage, or 20 feet (minimum); average of 2 adjoining lots or block frontage (maximum).', '20 feet or average rear yard setback on block, but no less than 10 feet.', '5 feet minimum, 15 feet combined for detached principal; 0 feet for attached principal (except 5 feet minimum when adjacent to detached structure, combined 15 feet).', 'Refer to general off-street parking requirements in § 120-173 of the Zoning Code.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r-1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'rochester') AND pu.name IN ('Single-family detached dwellings', 'Single-family attached dwellings', 'Family and group family day-care homes', 'Adult family day-care homes', 'Places of worship', 'Convents and rectories', 'Home occupations', 'Office (in existing nonresidential structure, 6:00 a.m. - 9:00 p.m.)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'rochester'), 'R-2', 'r-2', 'Medium-Density Residential District', 'The R-2 Medium-Density Residential District provides a mix of housing choices, including single-family, two-family, and multifamily residential, with bulk and density regulations that maintain a lower-density scale, located proximate to neighborhood-scale shopping and service opportunities.', 35, NULL, '[object Object]', 50, 'Average of 2 adjoining lots or block frontage, or 20 feet.', '10 feet.', '5 feet minimum, 15 feet combined for detached principal; 10 feet minimum, 25 feet combined for principal use or structure.', 'Refer to general off-street parking requirements in § 120-173 of the Zoning Code.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r-2' AND z.city_id = (SELECT id FROM cities WHERE slug = 'rochester') AND pu.name IN ('Single-family detached dwellings', 'Single-family attached dwellings', 'Two-family dwellings', 'Family and group family day-care homes', 'Adult family day-care homes', 'Places of worship', 'Convents and rectories', 'Home occupations', 'Office (in existing nonresidential structure, 6:00 a.m. - 9:00 p.m.)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'rochester'), 'R-3', 'r-3', 'High-Density Residential District', 'The R-3 High-Density Residential District protects, preserves, and enhances existing residential areas of higher density, including multifamily dwellings mixed with other housing types, and accommodates higher-density housing while maintaining and enhancing existing residential areas.', 'Two times the width of the lot frontage for principal uses; 15 feet for detached accessory uses.', NULL, '[object Object]', 50, 'Average of block or 20 feet (whichever is more), but no more than 5 feet larger than average of 2 adjoining lots.', '1/3 the building height or 20 feet, whichever is greater.', '5 feet minimum, 15 feet combined for detached principal; 1/3 building height or 10 feet (whichever is greater) for multifamily principal.', 'Refer to general off-street parking requirements in § 120-173 of the Zoning Code.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r-3' AND z.city_id = (SELECT id FROM cities WHERE slug = 'rochester') AND pu.name IN ('Single-family detached dwellings', 'Single-family attached dwellings', 'Two-family dwellings', 'Multifamily dwellings', 'Live-work space', 'Family and group family day-care homes', 'Adult family day-care homes', 'Places of worship', 'Convents and rectories', 'Home occupations', 'Office (in existing nonresidential structure, 6:00 a.m. - 9:00 p.m.)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'rochester'), 'C-1', 'c-1', 'Neighborhood Center District', 'The C-1 Neighborhood Center District provides for small-scale commercial uses offering primarily convenience shopping and services for adjacent residential areas, with low intensity and unobtrusive operations compatible with the surrounding neighborhood.', NULL, NULL, NULL, NULL, '0-5 feet or average of corridor/district, no more than 5 feet larger/smaller than average of 2 adjoining lots.', '0 feet unless adjacent to a residential district, then same as adjacent residential district.', '0 feet unless adjacent to a residential district, then same as adjacent residential district.', 'Refer to general off-street parking requirements in § 120-173 of the Zoning Code.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
