INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'rochester'), 'M-1', 'm-1', 'Industrial District', 'The M-1 Industrial District promotes the retention and growth of employment opportunities by providing areas where a broad range of industrial uses may locate and where options for complementary uses exist in older two-story and multistory buildings.', NULL, NULL, NULL, NULL, 'N/A unless adjacent to a residential district, then same as required front yard setback in residential district.', 'N/A unless adjacent to a residential district, then same as required rear yard setback in residential district.', 'N/A unless adjacent to a residential district, then same as required side yard setback in residential district.', 'Refer to general off-street parking requirements in § 120-173 of the Zoning Code; special permit uses may have parking requirements waived or modified.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
